import React, { useCallback } from 'react';
import { View, Text, StyleSheet, TouchableOpacity } from 'react-native';
import * as Sentry from '@sentry/react-native';
import { NavigationContainer } from '@react-navigation/native';
import { createNativeStackNavigator } from '@react-navigation/native-stack';

import { usePushNotifications } from './src/hooks/usePushNotifications';
import { AuthProvider, useAuth } from './src/contexts/AuthContext';
import { SocketProvider } from './src/contexts/SocketContext';

// Screens & Navigators
import AuthScreen from './src/screens/AuthScreen';
import MainTabs from './src/navigation/MainTabs';

// ─── Sentry Init ──────────────────────────────────────────────────────────────
Sentry.init({
  dsn: process.env.EXPO_PUBLIC_SENTRY_DSN,
  environment: process.env.EXPO_PUBLIC_ENV ?? 'development',
  tracesSampleRate: 0.2,
  enableNativeFramesTracking: true,
  attachStacktrace: true,
});

const Stack = createNativeStackNavigator();

// ─── Root Navigator (Switches Auth/App) ───────────────────────────────────────
function RootNavigator() {
  const { isAuthenticated, isLoading } = useAuth();

  if (isLoading) {
    // Basic splash while loading token
    return (
      <View style={styles.errorScreen}>
        <Text style={{color: '#64748b'}}>Loading...</Text>
      </View>
    );
  }

  return (
    <NavigationContainer>
      <Stack.Navigator screenOptions={{ headerShown: false }}>
        {isAuthenticated ? (
          <Stack.Screen name="AppTabs" component={MainTabs} />
        ) : (
          <Stack.Screen name="Auth" component={AuthScreen} />
        )}
      </Stack.Navigator>
    </NavigationContainer>
  );
}

// ─── ErrorBoundary ────────────────────────────────────────────────────────────
class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError() {
    return { hasError: true };
  }

  componentDidCatch(error, errorInfo) {
    Sentry.captureException(error, { extra: errorInfo });
  }

  render() {
    if (this.state.hasError) {
      return (
        <View style={styles.errorScreen}>
          <Text style={styles.errorTitle}>Something went wrong</Text>
          <Text style={styles.errorBody}>
            Our team has been notified. Please restart the app.
          </Text>
          <TouchableOpacity
            style={styles.restartBtn}
            onPress={() => this.setState({ hasError: false })}
          >
            <Text style={styles.restartBtnText}>Try Again</Text>
          </TouchableOpacity>
        </View>
      );
    }
    return this.props.children;
  }
}

// ─── Root export — wrapped with Contexts & Sentry ─────────────────────────────
function App() {
  return (
    <ErrorBoundary>
      <AuthProvider>
        <SocketProvider>
          <RootNavigator />
        </SocketProvider>
      </AuthProvider>
    </ErrorBoundary>
  );
}

export default Sentry.wrap(App);

const styles = StyleSheet.create({
  errorScreen: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
    backgroundColor: '#f8fafc',
    padding: 32,
  },
  errorTitle:   { fontSize: 22, fontWeight: '700', color: '#0f172a', marginBottom: 12 },
  errorBody:    { fontSize: 14, color: '#64748b', textAlign: 'center', lineHeight: 22 },
  restartBtn: {
    marginTop: 24,
    backgroundColor: '#0ea5e9',
    paddingHorizontal: 28,
    paddingVertical: 12,
    borderRadius: 10,
  },
  restartBtnText: { color: '#fff', fontWeight: '700', fontSize: 15 },
});
